use serde::{Serialize, Deserialize};
use std::fs::{File, OpenOptions};
use std::io::{self, Write, Read};
use std::path::Path;

#[derive(Serialize, Deserialize, Debug)]
enum Theme {
    Light,
    Dark,
}

#[derive(Serialize, Deserialize, Debug)]
struct Preferences {
    theme: Theme,
    font_size: u32,
    notifications_enabled: bool,
}

struct Cache {
    file_path: String,
}

impl Cache {
    fn new(file_path: &str) -> Self {
        Cache {
            file_path: file_path.to_string(),
        }
    }

    fn save(&self, preferences: &Preferences) -> io::Result<()> {
        let file = OpenOptions::new()
            .write(true)
            .create(true)
            .truncate(true)
            .open(&self.file_path)?;

        let encoded: Vec<u8> = bincode::serialize(preferences)?;
        file.write_all(&encoded)?;
        Ok(())
    }

    fn load(&self) -> io::Result<Preferences> {
        let path = Path::new(&self.file_path);
        if !path.exists() {
            return Err(io::Error::new(io::ErrorKind::NotFound, "Cache file not found"));
        }

        let mut file = File::open(&self.file_path)?;
        let mut buffer = Vec::new();
        file.read_to_end(&mut buffer)?;

        let preferences: Preferences = bincode::deserialize(&buffer)?;
        Ok(preferences)
    }
}

